        foreach ($f in $fl) {
            [void]$sb.AppendLine("| $($f.Name) | $($f.Runs) | $($f.Passed) | $($f.Failed) |")
        }
    }
    [void]$sb.AppendLine('')

    # Per-file breakdown
    [void]$sb.AppendLine('## Per-file Breakdown')
    [void]$sb.AppendLine('')
    [void]$sb.AppendLine('| File | Format | Tests | Passed | Failed | Skipped | Duration (s) |')
