        $script:WorkflowText | Should -Match 'needs:\s*pester'
    }
    It 'both jobs run on ubuntu-latest' {
        $matches = [regex]::Matches($script:WorkflowText, 'runs-on:\s*ubuntu-latest')
        $matches.Count | Should -BeGreaterOrEqual 2
    }
